BEGIN;
CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, username VARCHAR(100) NOT NULL UNIQUE, email VARCHAR(255) NOT NULL UNIQUE, password_hash TEXT NOT NULL, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS topics (id INTEGER PRIMARY KEY, name TEXT NOT NULL, questions_type VARCHAR(20) NOT NULL DEFAULT 'short');
CREATE TABLE IF NOT EXISTS variants (id SERIAL PRIMARY KEY, name TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS questions (id SERIAL PRIMARY KEY, text TEXT NOT NULL, body TEXT, image TEXT, correct_answer TEXT DEFAULT '', answer_type VARCHAR(20) NOT NULL DEFAULT 'short', topic_id INTEGER REFERENCES topics (id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS questions_variants (question_id INTEGER NOT NULL REFERENCES questions (id) ON DELETE CASCADE, variant_id INTEGER NOT NULL REFERENCES variants (id) ON DELETE CASCADE, position INTEGER NOT NULL DEFAULT 0, PRIMARY KEY (question_id, variant_id));
CREATE TABLE IF NOT EXISTS attempts (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users (id) ON DELETE CASCADE, variant_id INTEGER NOT NULL REFERENCES variants (id) ON DELETE CASCADE, total_questions INTEGER NOT NULL, correct_questions INTEGER NOT NULL, successful BOOLEAN NOT NULL, created_at TIMESTAMP DEFAULT NOW());

