INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (101, 'Укажите варианты ответов, в которых верно определена грамматическая основа в одном из предложений или в одной из частей сложного предложения текста. Запишите номера ответов.', '(1) Узкая лесная полоса протянулась вдоль реки и скрылась за холмом, а по берегам замерли кусты и молодые ивы.
(2) В верхней части старого дома были расположены редкие рукописи и старинные карты.
(3) Сосны, старожилы здешних мест, растут на сухом пригорке.
(4) Домики, которые будут находиться у самой опушки, уже обозначили на плане, и рабочие начали расчистку.
(5) Сбор ягод считался у нас делом семейным, когда наступала осень.

1) полоса протянулась (предложение 1)
2) расположены части (предложение 2)
3) растут (предложение 3)
4) которые будут находиться (предложение 4)
5) сбор являлся (предложение 5)', NULL, '14', 'short', 1) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (102, 'Укажите варианты ответов, в которых даны верные характеристики предложений текста. Запишите номера ответов.', '(1) Узкая лесная полоса протянулась вдоль реки и скрылась за холмом, а по берегам замерли кусты и молодые ивы.
(2) В верхней части старого дома были расположены редкие рукописи и старинные карты.
(3) Сосны, старожилы здешних мест, растут на сухом пригорке.
(4) Домики, которые будут находиться у самой опушки, уже обозначили на плане, и рабочие начали расчистку.
(5) Сбор ягод считался у нас делом семейным, когда наступала осень.

1) Вторая часть сложного предложения 1 осложнена однородными членами предложения.
2) В предложении 2 содержится простое глагольное сказуемое.
3) Предложение 3 осложнено обособленным согласованным приложением.
4) Вторая часть сложного предложения 4 представлена односоставным безличным предложением.
5) Предложение 5 бессоюзное сложное предложение.', NULL, '13', 'short', 2) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (103, 'Установите соответствие между пунктуационными правилами и предложениями, которые могут служить примерами для приведённых правил. Запишите цифры в порядке АБВ.', 'ПУНКТУАЦИОННЫЕ ПРАВИЛА

А) В неполном предложении на месте пропущенного члена предложения ставится тире.
Б) Между частями сложного бессоюзного предложения ставится двоеточие, если вторая часть поясняет, дополняет первую.
В) В сложноподчиненном предложении между главным и придаточным предложением ставится запятая.

ПРЕДЛОЖЕНИЯ

1) Зимой звёзды на небе ярко блестят — жди лютой стужи.
2) Создание интерактивных электронных учебников нового поколения — одно из перспективных направлений в модернизации учебного процесса, которое позволит не только повысить интерес обучающихся к предмету, но и улучшить качество обучения.
3) Виктор Петрович удивился: почему его никто не ищет?
4) Всюду: на листьях деревьев, на траве, на крышах домов и сараев, покрытых камышом, — до полудня лежала обильная роса, и мы не стали торопиться с выходом в поле.
5) По одну сторону дороги стройными рядами тянулись тонкие хрупкие берёзки, а по другую — могучие и солидные дубы-великаны.', NULL, '532', 'short', 3) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (104, 'Расставьте знаки препинания. Укажите цифры, на месте которых должно стоять тире.', 'В нашей стране первая консерватория открылась (1) в 1862 году в Петербурге. Её основатель (2) Антон Григорьевич Рубинштейн. Прекрасный композитор и выдающийся пианист (3) неутомимый пропагандист музыкальной культуры и музыкальных знаний (4) так характеризовали его современники. Обязательное условие для поступления в консерваторию (5) определённый уровень профессиональной подготовки. Взрослые ученики часто совмещали музыкальные занятия с обучением в университете или со службой. Для младших существовали научные классы (6) в которых ученики получали (7) примерно такое же общее образование (8) какое давала гимназия.', NULL, '245', 'short', 4) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (105, 'Укажите варианты ответов, в которых дано верное объяснение написания выделенного слова. Запишите номера ответов.', '1) РОСКОШНЫЙ — в корне слова с чередующейся гласной перед -С- пишется буква О.
2) ПРИМОРСКИЙ — написание приставки определяется её значением — расположение вблизи.
3) ЧИСТОСЕРДЕЧНЫЙ — сложное имя прилагательное, образованное на основе подчинительного словосочетания, пишется слитно.
4) БЛЕДНОЛИЦЫЙ (мальчик) — в суффиксе имени прилагательного после Ц пишется буква Ы.
5) (отнюдь) НЕ РЕШИТЕЛЬНЫЙ (поступок) — раздельное написание частицы НЕ с именем прилагательным определяется словом, усиливающим отрицание.', NULL, '235', 'short', 5) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (106, 'Прочитайте текст. Вставьте пропущенные буквы. Укажите все цифры, на месте которых пишется буква О.', 'Солнечный свет охват(1)..вал и с(2)..гревал океаны сентябрьского воздуха над ещ(3).. спящей и сумр(4)..чной стр(5)..ной. Но через полчаса земля начала (6)..деваться в б(7)..грянец, в ржавчину сжатых п(8)..лей, в сырую и яркую зелень озимых, в пурпур осин(9)..вых листьев и желтизну трепещущих от ветра берёз.', NULL, '2689', 'short', 6) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (107, 'Раскройте скобки и запишите слово в соответствующей форме, соблюдая нормы современного русского литературного языка.', 'Самому древнему маяку из действующих до наших дней более (шестьсот) лет.', NULL, 'шестисот', 'short', 7) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (108, 'Синтаксический анализ. Замените словосочетание, построенное на основе управления, синонимичным словосочетанием со связью примыкание. Напишите получившееся словосочетание, соблюдая нормы современного русского литературного языка.', 'Замените словосочетание «отвечал с запинками», построенное на основе управления, синонимичным словосочетанием со связью примыкание.', NULL, 'отвечал запинаясь', 'short', 8) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (109, 'Анализ содержания текста. Какие из высказываний соответствуют содержанию текста? Укажите номера ответов.', '(1) В нашей паре я был ведущим, а Павлик ведомым. (2) Недоброжелатели считали, что Павлик был приложением ко мне. (3) На первый взгляд так оно и было. (4) Меня нельзя было приглашать на день рождения без Павлика. (5) Я покинул футбольную дворовую команду, где считался лучшим бомбардиром, когда Павлика отказались взять хотя бы запасным, и вернулся вместе с ним. (6) Так возникла иллюзия нашего неравенства. (7) На самом деле ни один из нас не зависел от другого, но душевное превосходство было на стороне Павлика. (8) Его нравственный кодекс был строже и чище моего. (9) Павлик не признавал сделок с совестью, тут он становился беспощаден.

(10) Однажды я на своей шкуре испытал, насколько непримиримым может быть мягкий, покладистый Павлик. (11) На уроках немецкого я чувствовал себя принцем. (12) Я с детства хорошо знал язык, и наша «немка» Елена Францевна души во мне не чаяла и никогда не спрашивала у меня уроков. (13) Вдруг ни с того ни с сего она вызвала меня к доске. (14) Как раз перед этим я пропустил несколько дней и не знал о домашнем задании. (15) Поначалу всё шло хорошо: я проспрягал какой-то глагол, отбарабанил предлоги, прочёл текст и пересказал его.

— (16) Прекрасно, — поджала губы Елена Францевна. — (17) Теперь стихотворение.

— (18) Какое стихотворение?

— (19) То, которое задано! — отчеканила она ледяным тоном.

— (20) А вы разве задавали?

— (21) Привык на уроках ворон считать! — завелась она с пол-оборота. — (22) Здоровенный парень, а дисциплина...

— (23) Да я же болел!

— (24) Да, ты отсутствовал. (25) А спросить у товарищей, что задано, мозгов не хватило?

(26) Взял бы да и сказал: не хватило. (27) Ну что она могла мне сделать? (28) О домашних заданиях я спрашивал у Павлика, а он ни словом не обмолвился о стихотворении. (29) Забыл, наверное. (30) Я так и сказал Елене Францевне.

— (31) Встань! — приказала Павлику немка. — (32) Это правда?

(33) Он молча наклонил голову. (34) И я тут же понял, что это неправда. (35) Как раз о немецком я его не спрашивал...

(36) Елена Францевна перенесла свой гнев на Павлика. (37) Он слушал её молча, не оправдываясь и не огрызаясь, словно всё это нисколько его не касалось. (38) Спустив пары, немка угомонилась и предложила мне прочесть любое стихотворение на выбор... (39) Я получил «отлично».

(40) Вот так всё и обошлось. (41) Когда, довольный и счастливый, я вернулся на своё место, Павлика, к моему удивлению, не оказалось рядом. (42) Он сидел за пустой партой далеко от меня.

— (43) Ты чего это?..

(44) Он не ответил. (45) У него были какие-то странные глаза — красные и налитые влагой. (46) Я никогда не видел Павлика плачущим. (47) Даже после самых жестоких, неравных и неудачных драк, когда и самые сильные ребята плачут, он не плакал.

— (48) Брось! — сказал я. — (49) Стоит ли из-за учительницы?

(50) Он молчал и глядел мимо меня. (51) Какое ему дело до Елены Францевны, он и думать о ней забыл. (52) Его предал друг. (53) Спокойно, обыденно и публично, ради грошовой выгоды предал человек, за которого он, не раздумывая, пошёл бы в огонь и в воду.

(54) Никому не хочется признаваться в собственной низости. (55) Я стал уговаривать себя, что поступил правильно. (56) Ну покричала на него немка, подумаешь, несчастье! (57) Стоит ли вообще придавать значение подобной чепухе?.. (58) И всё же, окажись Павлик на моем месте, назвал бы он меня? (59) Нет! (60) Он скорее проглотил бы собственный язык. (61) Когда прозвучал звонок, я подавил желание броситься к нему, признавая тем самым свою вину и готовность принять кару.

(62) Потом было немало случаев, когда мы могли бы вернуться к прежней дружбе, но Павлик не хотел этого: ему не нужен был тот человек, каким я вдруг раскрылся на уроке немецкого.

1) Павлик не мог смириться с ролью ведомого в дружбе.
2) Рассказчик хорошо знал немецкий язык, поэтому учительница любила его и редко спрашивала домашнее задание.
3) Елена Францевна поставила рассказчику двойку за невыученное стихотворение.
4) Рассказчик никогда не узнавал домашнего задания у Павлика.
5) Павлик не простил другу предательства.', NULL, '25', 'short', 9) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (110, 'Анализ средств выразительности. Укажите варианты ответов, в которых средством выразительности речи является фразеологизм.', '(1) В нашей паре я был ведущим, а Павлик ведомым. (2) Недоброжелатели считали, что Павлик был приложением ко мне. (3) На первый взгляд так оно и было. (4) Меня нельзя было приглашать на день рождения без Павлика. (5) Я покинул футбольную дворовую команду, где считался лучшим бомбардиром, когда Павлика отказались взять хотя бы запасным, и вернулся вместе с ним. (6) Так возникла иллюзия нашего неравенства. (7) На самом деле ни один из нас не зависел от другого, но душевное превосходство было на стороне Павлика. (8) Его нравственный кодекс был строже и чище моего. (9) Павлик не признавал сделок с совестью, тут он становился беспощаден.

(10) Однажды я на своей шкуре испытал, насколько непримиримым может быть мягкий, покладистый Павлик. (11) На уроках немецкого я чувствовал себя принцем. (12) Я с детства хорошо знал язык, и наша «немка» Елена Францевна души во мне не чаяла и никогда не спрашивала у меня уроков. (13) Вдруг ни с того ни с сего она вызвала меня к доске. (14) Как раз перед этим я пропустил несколько дней и не знал о домашнем задании. (15) Поначалу всё шло хорошо: я проспрягал какой-то глагол, отбарабанил предлоги, прочёл текст и пересказал его.

— (16) Прекрасно, — поджала губы Елена Францевна. — (17) Теперь стихотворение.

— (18) Какое стихотворение?

— (19) То, которое задано! — отчеканила она ледяным тоном.

— (20) А вы разве задавали?

— (21) Привык на уроках ворон считать! — завелась она с пол-оборота. — (22) Здоровенный парень, а дисциплина...

— (23) Да я же болел!

— (24) Да, ты отсутствовал. (25) А спросить у товарищей, что задано, мозгов не хватило?

(26) Взял бы да и сказал: не хватило. (27) Ну что она могла мне сделать? (28) О домашних заданиях я спрашивал у Павлика, а он ни словом не обмолвился о стихотворении. (29) Забыл, наверное. (30) Я так и сказал Елене Францевне.

— (31) Встань! — приказала Павлику немка. — (32) Это правда?

(33) Он молча наклонил голову. (34) И я тут же понял, что это неправда. (35) Как раз о немецком я его не спрашивал...

(36) Елена Францевна перенесла свой гнев на Павлика. (37) Он слушал её молча, не оправдываясь и не огрызаясь, словно всё это нисколько его не касалось. (38) Спустив пары, немка угомонилась и предложила мне прочесть любое стихотворение на выбор... (39) Я получил «отлично».

(40) Вот так всё и обошлось. (41) Когда, довольный и счастливый, я вернулся на своё место, Павлика, к моему удивлению, не оказалось рядом. (42) Он сидел за пустой партой далеко от меня.

— (43) Ты чего это?..

(44) Он не ответил. (45) У него были какие-то странные глаза — красные и налитые влагой. (46) Я никогда не видел Павлика плачущим. (47) Даже после самых жестоких, неравных и неудачных драк, когда и самые сильные ребята плачут, он не плакал.

— (48) Брось! — сказал я. — (49) Стоит ли из-за учительницы?

(50) Он молчал и глядел мимо меня. (51) Какое ему дело до Елены Францевны, он и думать о ней забыл. (52) Его предал друг. (53) Спокойно, обыденно и публично, ради грошовой выгоды предал человек, за которого он, не раздумывая, пошёл бы в огонь и в воду.

(54) Никому не хочется признаваться в собственной низости. (55) Я стал уговаривать себя, что поступил правильно. (56) Ну покричала на него немка, подумаешь, несчастье! (57) Стоит ли вообще придавать значение подобной чепухе?.. (58) И всё же, окажись Павлик на моем месте, назвал бы он меня? (59) Нет! (60) Он скорее проглотил бы собственный язык. (61) Когда прозвучал звонок, я подавил желание броситься к нему, признавая тем самым свою вину и готовность принять кару.

(62) Потом было немало случаев, когда мы могли бы вернуться к прежней дружбе, но Павлик не хотел этого: ему не нужен был тот человек, каким я вдруг раскрылся на уроке немецкого.

1) На уроках немецкого я чувствовал себя принцем.
2) Даже после самых жестоких, неравных и неудачных драк, когда и самые сильные ребята плачут, он не плакал.
3) Недоброжелатели считали, что Павлик был приложением ко мне.
4) Я с детства хорошо знал язык, и наша «немка» Елена Францевна души во мне не чаяла и никогда не спрашивала у меня уроков.
5) Вдруг ни с того ни с сего она вызвала меня к доске.', NULL, '45', 'short', 10) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (111, 'Лексический анализ. Выпишите синоним из указанного диапазона предложений.', '(1) В нашей паре я был ведущим, а Павлик ведомым. (2) Недоброжелатели считали, что Павлик был приложением ко мне. (3) На первый взгляд так оно и было. (4) Меня нельзя было приглашать на день рождения без Павлика. (5) Я покинул футбольную дворовую команду, где считался лучшим бомбардиром, когда Павлика отказались взять хотя бы запасным, и вернулся вместе с ним. (6) Так возникла иллюзия нашего неравенства. (7) На самом деле ни один из нас не зависел от другого, но душевное превосходство было на стороне Павлика. (8) Его нравственный кодекс был строже и чище моего. (9) Павлик не признавал сделок с совестью, тут он становился беспощаден.

(10) Однажды я на своей шкуре испытал, насколько непримиримым может быть мягкий, покладистый Павлик. (11) На уроках немецкого я чувствовал себя принцем. (12) Я с детства хорошо знал язык, и наша «немка» Елена Францевна души во мне не чаяла и никогда не спрашивала у меня уроков. (13) Вдруг ни с того ни с сего она вызвала меня к доске. (14) Как раз перед этим я пропустил несколько дней и не знал о домашнем задании. (15) Поначалу всё шло хорошо: я проспрягал какой-то глагол, отбарабанил предлоги, прочёл текст и пересказал его.

— (16) Прекрасно, — поджала губы Елена Францевна. — (17) Теперь стихотворение.

— (18) Какое стихотворение?

— (19) То, которое задано! — отчеканила она ледяным тоном.

— (20) А вы разве задавали?

— (21) Привык на уроках ворон считать! — завелась она с пол-оборота. — (22) Здоровенный парень, а дисциплина...

— (23) Да я же болел!

— (24) Да, ты отсутствовал. (25) А спросить у товарищей, что задано, мозгов не хватило?

(26) Взял бы да и сказал: не хватило. (27) Ну что она могла мне сделать? (28) О домашних заданиях я спрашивал у Павлика, а он ни словом не обмолвился о стихотворении. (29) Забыл, наверное. (30) Я так и сказал Елене Францевне.

— (31) Встань! — приказала Павлику немка. — (32) Это правда?

(33) Он молча наклонил голову. (34) И я тут же понял, что это неправда. (35) Как раз о немецком я его не спрашивал...

(36) Елена Францевна перенесла свой гнев на Павлика. (37) Он слушал её молча, не оправдываясь и не огрызаясь, словно всё это нисколько его не касалось. (38) Спустив пары, немка угомонилась и предложила мне прочесть любое стихотворение на выбор... (39) Я получил «отлично».

(40) Вот так всё и обошлось. (41) Когда, довольный и счастливый, я вернулся на своё место, Павлика, к моему удивлению, не оказалось рядом. (42) Он сидел за пустой партой далеко от меня.

— (43) Ты чего это?..

(44) Он не ответил. (45) У него были какие-то странные глаза — красные и налитые влагой. (46) Я никогда не видел Павлика плачущим. (47) Даже после самых жестоких, неравных и неудачных драк, когда и самые сильные ребята плачут, он не плакал.

— (48) Брось! — сказал я. — (49) Стоит ли из-за учительницы?

(50) Он молчал и глядел мимо меня. (51) Какое ему дело до Елены Францевны, он и думать о ней забыл. (52) Его предал друг. (53) Спокойно, обыденно и публично, ради грошовой выгоды предал человек, за которого он, не раздумывая, пошёл бы в огонь и в воду.

(54) Никому не хочется признаваться в собственной низости. (55) Я стал уговаривать себя, что поступил правильно. (56) Ну покричала на него немка, подумаешь, несчастье! (57) Стоит ли вообще придавать значение подобной чепухе?.. (58) И всё же, окажись Павлик на моем месте, назвал бы он меня? (59) Нет! (60) Он скорее проглотил бы собственный язык. (61) Когда прозвучал звонок, я подавил желание броситься к нему, признавая тем самым свою вину и готовность принять кару.

(62) Потом было немало случаев, когда мы могли бы вернуться к прежней дружбе, но Павлик не хотел этого: ему не нужен был тот человек, каким я вдруг раскрылся на уроке немецкого.

Среди предложений 21–25 найдите синоним к слову ДРУГ из предложения 52. Выпишите этот синоним.', NULL, 'товарищей', 'short', 11) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (112, 'Используя прочитанный текст, выполните на отдельном листе ТОЛЬКО ОДНО из заданий (1, 2 или 3). Перед написанием сочинения запишите номер выбранного задания (1, 2 или 3).', '1. Напишите сочинение-рассуждение на тему: «Какие средства языка использовал автор, чтобы создать образы мальчишек?».

Приведите в сочинении два примера из прочитанного текста, подтверждающих Ваши рассуждения. Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой полностью переписанный или пересказанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком.

2. Напишите сочинение-рассуждение. Объясните, как Вы понимаете смысл смысл финала текста: «Но он рад был происшествию, потому что Витёк его зауважал и Сивка оказался Сивкой, а не чем-то вроде...».

Приведите в сочинении два примера из прочитанного текста, подтверждающих Ваши рассуждения. Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой полностью переписанный или пересказанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком.

3. Напишите сочинение-рассуждение на тему «Как можно завоевать уважение?». Дайте обоснованный ответ на вопрос, сформулированный в теме сочинения.

Приведите в сочинении два примера, подтверждающих Ваши рассуждения: один пример — из прочитанного текста, а другой — из прочитанного текста или из Вашего жизненного опыта. (Не учитываются примеры, источниками которых являются комикс, аниме, манга, фанфик, графический роман, компьютерная игра и другие подобные виды представления информации.) Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой пересказанный или полностью переписанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком.', NULL, '', 'long', 12) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (201, 'Укажите варианты ответов, в которых верно определена грамматическая основа в одном из предложений или в одной из частей сложного предложения текста. Запишите номера ответов.', '(1) Вечером на площади зажглись фонари, и влажный воздух сразу стал теплее.
(2) По краям аллеи были высажены молодые липы.
(3) Ребята, участники школьного театра, готовились к премьере.
(4) Люди, которые пришли пораньше, уже заняли первые ряды.
(5) Праздник обещал запомниться надолго.

1) фонари зажглись (предложение 1)
2) были высажены липы (предложение 2)
3) участники готовились (предложение 3)
4) которые пришли (предложение 4)
5) праздник обещал (предложение 5)', NULL, '145', 'short', 1) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (202, 'Укажите варианты ответов, в которых даны верные характеристики предложений текста. Запишите номера ответов.', '(1) Вечером на площади зажглись фонари, и влажный воздух сразу стал теплее.
(2) По краям аллеи были высажены молодые липы.
(3) Ребята, участники школьного театра, готовились к премьере.
(4) Люди, которые пришли пораньше, уже заняли первые ряды.
(5) Праздник обещал запомниться надолго.

1) Предложение 1 сложносочинённое.
2) В предложении 2 сказуемое составное именное.
3) Предложение 3 осложнено приложением.
4) В предложении 4 есть придаточное определительное.
5) Предложение 5 односоставное безличное.', NULL, '134', 'short', 2) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (203, 'Установите соответствие между пунктуационными правилами и предложениями, которые могут служить примерами для приведённых правил. Запишите цифры в порядке АБВ.', 'ПУНКТУАЦИОННЫЕ ПРАВИЛА

А) Между подлежащим и сказуемым ставится тире, если оба главных члена выражены существительными в именительном падеже.
Б) Между частями сложного бессоюзного предложения ставится двоеточие, если вторая часть указывает на причину того, о чём говорится в первой.
В) В сложноподчинённом предложении между главным и придаточным предложением ставится запятая.

ПРЕДЛОЖЕНИЯ

1) Учение — путь к мастерству.
2) Я остановился: впереди послышались шаги.
3) Когда ветер стих, лодка мягко коснулась берега.
4) Летом луга покрываются цветами, и воздух становится особенно душистым.
5) Утром в саду щебетали птицы.', NULL, '123', 'short', 3) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (204, 'Расставьте знаки препинания. Укажите цифры, на месте которых должно стоять тире.', 'Наш лучший учитель (1) Иван Петрович. Его главное качество (2) терпение. Чтение хороших книг (3) верный путь к развитию. Вечером мы вышли на крыльцо (4) и долго смотрели на сад. Осенняя тишина (5) настоящее чудо.', NULL, '1235', 'short', 4) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (205, 'Укажите варианты ответов, в которых дано верное объяснение написания выделенного слова. Запишите номера ответов.', '1) ПРИШКОЛЬНЫЙ — приставка ПРИ- имеет значение близости.
2) БЕСШУМНЫЙ — на конце приставки перед глухим согласным пишется С.
3) ЦЫПЛЁНОК — после Ц в корне всегда пишется И.
4) НЕ СДЕЛАННАЯ МНОЙ работа — причастие с зависимым словом пишется раздельно.
5) КОСНУТЬСЯ — в корне с чередованием пишется О, если после корня нет суффикса -А-.', NULL, '145', 'short', 5) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (206, 'Прочитайте текст. Вставьте пропущенные буквы. Укажите все цифры, на месте которых пишется буква О.', 'Ранним утром мы выск(1)..чили из дома, быстро прик(2)..снулись к холодной воде родника и пошли по тр(3)..пинке к старому м(4)..сту. Солнце заг(5)..ралось над лесом всё ярче.', NULL, '12345', 'short', 6) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (207, 'Раскройте скобки и запишите слово в соответствующей форме, соблюдая нормы современного русского литературного языка.', 'В коллекции музея более (семьсот) экспонатов.', NULL, 'семисот', 'short', 7) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (208, 'Синтаксический анализ. Замените словосочетание, построенное на основе управления, синонимичным словосочетанием со связью примыкание. Напишите получившееся словосочетание, соблюдая нормы современного русского литературного языка.', 'Замените словосочетание «говорил без умолку» синонимичным словосочетанием со связью примыкание.', NULL, 'говорил не умолкая', 'short', 8) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (209, 'Анализ содержания текста. Какие из высказываний соответствуют содержанию текста? Укажите номера ответов.', '(1) В школьной библиотеке работала Анна Сергеевна. (2) Она знала по имени почти каждого ученика и всегда помнила, какую книгу тот взял в прошлый раз. (3) Я заходил туда не столько за учебниками, сколько за разговорами. (4) Стоило мне появиться на пороге, как библиотекарь сразу понимала, в каком я настроении. (5) Если я молчал, она не тянула меня за язык и просто ставила на стол новую книгу. (6) Однажды я пришёл мрачнее тучи: на районной олимпиаде занял только второе место. (7) Мне казалось, что я сел в лужу перед всей школой. (8) Анна Сергеевна выслушала меня и сказала, что проигрыш — не повод бросать дело. (9) Потом она принесла старый сборник писем учёных и открыла страницу, где известный математик писал о своих провалах. (10) Я читал и понемногу успокаивался. (11) Оказалось, что даже сильные люди не идут к цели по прямой дороге. (12) Перед уходом библиотекарь улыбнулась и попросила вернуть книгу не раньше, чем я дочитаю её до конца. (13) С тех пор я перестал воспринимать каждую неудачу как конец света.

1) Рассказчик ходил в библиотеку только за учебниками.
2) Анна Сергеевна умела понять настроение рассказчика.
3) Рассказчик победил на районной олимпиаде.
4) Библиотекарь посоветовала ему бросить занятия.
5) После разговора с библиотекарем герой иначе стал смотреть на неудачи.', NULL, '25', 'short', 9) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (210, 'Анализ средств выразительности. Укажите варианты ответов, в которых средством выразительности речи является фразеологизм.', '(1) В школьной библиотеке работала Анна Сергеевна. (2) Она знала по имени почти каждого ученика и всегда помнила, какую книгу тот взял в прошлый раз. (3) Я заходил туда не столько за учебниками, сколько за разговорами. (4) Стоило мне появиться на пороге, как библиотекарь сразу понимала, в каком я настроении. (5) Если я молчал, она не тянула меня за язык и просто ставила на стол новую книгу. (6) Однажды я пришёл мрачнее тучи: на районной олимпиаде занял только второе место. (7) Мне казалось, что я сел в лужу перед всей школой. (8) Анна Сергеевна выслушала меня и сказала, что проигрыш — не повод бросать дело. (9) Потом она принесла старый сборник писем учёных и открыла страницу, где известный математик писал о своих провалах. (10) Я читал и понемногу успокаивался. (11) Оказалось, что даже сильные люди не идут к цели по прямой дороге. (12) Перед уходом библиотекарь улыбнулась и попросила вернуть книгу не раньше, чем я дочитаю её до конца. (13) С тех пор я перестал воспринимать каждую неудачу как конец света.

1) Я заходил туда не столько за учебниками, сколько за разговорами.
2) Если я молчал, она не тянула меня за язык.
3) Потом она принесла старый сборник писем учёных.
4) Мне казалось, что я сел в лужу перед всей школой.
5) Я читал и понемногу успокаивался.', NULL, '24', 'short', 10) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (211, 'Лексический анализ. Выпишите синоним из указанного диапазона предложений.', '(1) В школьной библиотеке работала Анна Сергеевна. (2) Она знала по имени почти каждого ученика и всегда помнила, какую книгу тот взял в прошлый раз. (3) Я заходил туда не столько за учебниками, сколько за разговорами. (4) Стоило мне появиться на пороге, как библиотекарь сразу понимала, в каком я настроении. (5) Если я молчал, она не тянула меня за язык и просто ставила на стол новую книгу. (6) Однажды я пришёл мрачнее тучи: на районной олимпиаде занял только второе место. (7) Мне казалось, что я сел в лужу перед всей школой. (8) Анна Сергеевна выслушала меня и сказала, что проигрыш — не повод бросать дело. (9) Потом она принесла старый сборник писем учёных и открыла страницу, где известный математик писал о своих провалах. (10) Я читал и понемногу успокаивался. (11) Оказалось, что даже сильные люди не идут к цели по прямой дороге. (12) Перед уходом библиотекарь улыбнулась и попросила вернуть книгу не раньше, чем я дочитаю её до конца. (13) С тех пор я перестал воспринимать каждую неудачу как конец света.

Среди предложений 8–13 найдите синоним к слову ПРОИГРЫШ из предложения 8. Выпишите этот синоним.', NULL, 'неудачу', 'short', 11) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (212, 'Используя прочитанный текст, выполните на отдельном листе ТОЛЬКО ОДНО из заданий (13.1, 13.2 или 13.3).', '13.1 Напишите сочинение-рассуждение на тему «Какую роль в тексте играют олицетворения?».

Дайте ответ на вопрос, сформулированный в теме сочинения.

Приведите в сочинении два примера из прочитанного текста, подтверждающих Ваши рассуждения. Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Сделайте вывод на основе Ваших рассуждений.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой полностью переписанный или пересказанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком, соблюдая нормы современного русского литературного языка.

13.2 Напишите сочинение-рассуждение. Объясните, как Вы понимаете финал данного текста: «Он бежал обратно к музыкальному училищу, к скрипке, к самому себе».

Дайте ответ на вопрос, сформулированный в теме сочинения.

Приведите в сочинении два примера из прочитанного текста, подтверждающих Ваши рассуждения. Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Сделайте вывод на основе Ваших рассуждений.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой полностью переписанный или пересказанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком, соблюдая нормы современного русского литературного языка.

13.3 Напишите сочинение-рассуждение на тему «Почему важно оставаться верным своим убеждениям?».

Дайте ответ на вопрос, сформулированный в теме сочинения.

Приведите в сочинении два примера из прочитанного текста, подтверждающих Ваши рассуждения. Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Сделайте вывод на основе Ваших рассуждений.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой полностью переписанный или пересказанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком, соблюдая нормы современного русского литературного языка.', NULL, '', 'long', 12) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (301, 'Укажите варианты ответов, в которых верно определена грамматическая основа в одном из предложений или в одной из частей сложного предложения текста. Запишите номера ответов.', '(1) Утром море блестело и казалось неподвижным.
(2) На горизонте были видны рыбацкие лодки.
(3) Чайки, вечные спутницы берега, кружили над водой.
(4) Люди, которые приехали на рассвете, уже расставляли снасти.
(5) День обещал быть тёплым.

1) море блестело (предложение 1)
2) на горизонте были видны (предложение 2)
3) спутницы кружили (предложение 3)
4) которые приехали (предложение 4)
5) день обещал (предложение 5)', NULL, '145', 'short', 1) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (302, 'Укажите варианты ответов, в которых даны верные характеристики предложений текста. Запишите номера ответов.', '(1) Утром море блестело и казалось неподвижным.
(2) На горизонте были видны рыбацкие лодки.
(3) Чайки, вечные спутницы берега, кружили над водой.
(4) Люди, которые приехали на рассвете, уже расставляли снасти.
(5) День обещал быть тёплым.

1) Предложение 1 осложнено однородными сказуемыми.
2) Предложение 2 является односоставным безличным.
3) Предложение 3 осложнено обособленным приложением.
4) В предложении 4 есть придаточное определительное.
5) Предложение 5 является сложносочинённым.', NULL, '134', 'short', 2) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (303, 'Установите соответствие между пунктуационными правилами и предложениями, которые могут служить примерами для приведённых правил. Запишите цифры в порядке АБВ.', 'ПУНКТУАЦИОННЫЕ ПРАВИЛА

А) В неполном предложении на месте пропущенного члена предложения ставится тире.
Б) Между частями сложного бессоюзного предложения ставится двоеточие, если вторая часть поясняет первую.
В) Между частями сложносочинённого предложения ставится запятая.

ПРЕДЛОЖЕНИЯ

1) Я остановился: впереди лежало поваленное дерево.
2) По одну сторону улицы тянулись клёны, а по другую — липы.
3) Мы долго ждали, но поезд всё не приходил.
4) Когда рассвело, дорога показалась совсем иной.
5) На столе лежали тетради: красные, синие, зелёные.', NULL, '213', 'short', 3) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (304, 'Расставьте знаки препинания. Укажите цифры, на месте которых должно стоять тире.', 'Наш главный помощник в походе (1) карта. Её составитель (2) опытный географ. Самое трудное в этом маршруте (3) не подъём, а длинный спуск. Внизу нас ждала река (4) и широкая поляна. Последняя остановка (5) у старой мельницы. Для уставших путников эта поляна (6) настоящий подарок.', NULL, '12356', 'short', 4) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (305, 'Укажите варианты ответов, в которых дано верное объяснение написания выделенного слова. Запишите номера ответов.', '1) ПРИБЕЖАТЬ — приставка ПРИ- пишется в значении «очень».
2) БЕЗЫМЯННЫЙ — после приставки на согласную вместо И пишется Ы.
3) ЦИРКУЛЬ — после Ц в корне всегда пишется Ы.
4) НЕ РЕШЁННЫЙ ВОВРЕМЯ вопрос — причастие с зависимым словом пишется раздельно.
5) ПРИМОРЬЕ — приставка ПРИ- пишется в значении близости к чему-либо.', NULL, '245', 'short', 5) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (306, 'Прочитайте текст. Вставьте пропущенные буквы. Укажите все цифры, на месте которых пишется буква О.', 'Мы к(1)..снулись ладонями холодной воды, заметили маленький р(2)..сток у берега и вск(3)..ре услышали ш(4)..рох в камышах. Над водой заг(5)..релось солнце, и туман начал рассеиваться.', NULL, '12345', 'short', 6) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (307, 'Раскройте скобки и запишите слово в соответствующей форме, соблюдая нормы современного русского литературного языка.', 'В зале собралось более (восемьсот) зрителей.', NULL, 'восьмисот', 'short', 7) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (308, 'Синтаксический анализ. Замените словосочетание, построенное на основе управления, синонимичным словосочетанием со связью примыкание. Напишите получившееся словосочетание, соблюдая нормы современного русского литературного языка.', 'Замените словосочетание «шёл без спешки» синонимичным словосочетанием со связью примыкание.', NULL, 'шёл не спеша', 'short', 8) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (309, 'Анализ содержания текста. Какие из высказываний соответствуют содержанию текста? Укажите номера ответов.', '(1) Каждую весну дед собирал во дворе дощечки и принимался мастерить скворечники. (2) Он вставал ни свет ни заря, чтобы закончить работу до жары. (3) Я сначала смотрел на него из окна и не понимал, зачем тратить время на птиц. (4) Но однажды дед позвал меня в мастерскую и дал маленький молоток. (5) С этого дня дело пошло веселее. (6) Мы вместе выбирали доски, спорили из-за размеров крыши и смеялись, когда гвозди упрямо гнулись. (7) Дед не ругался и никогда не делал всё за меня. (8) Он только повторял, что хороший мастер должен семь раз отмерить. (9) Когда скворечник наконец повис на яблоне, я ходил вокруг него как именинник. (10) Через неделю в домик заселилась первая пара скворцов. (11) Тогда я понял, что мы строили не просто коробку, а жильё для живых существ. (12) С тех пор весеннюю работу я ждал не меньше деда.

1) Дед мастерил скворечники только ради продажи.
2) Сначала рассказчик не понимал увлечения деда.
3) Дед постоянно сердился на внука.
4) Скворечник так и остался лежать в мастерской.
5) После этой истории герой стал ждать весеннюю работу.', NULL, '25', 'short', 9) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (310, 'Анализ средств выразительности. Укажите варианты ответов, в которых средством выразительности речи является фразеологизм.', '(1) Каждую весну дед собирал во дворе дощечки и принимался мастерить скворечники. (2) Он вставал ни свет ни заря, чтобы закончить работу до жары. (3) Я сначала смотрел на него из окна и не понимал, зачем тратить время на птиц. (4) Но однажды дед позвал меня в мастерскую и дал маленький молоток. (5) С этого дня дело пошло веселее. (6) Мы вместе выбирали доски, спорили из-за размеров крыши и смеялись, когда гвозди упрямо гнулись. (7) Дед не ругался и никогда не делал всё за меня. (8) Он только повторял, что хороший мастер должен семь раз отмерить. (9) Когда скворечник наконец повис на яблоне, я ходил вокруг него как именинник. (10) Через неделю в домик заселилась первая пара скворцов. (11) Тогда я понял, что мы строили не просто коробку, а жильё для живых существ. (12) С тех пор весеннюю работу я ждал не меньше деда.

1) Он вставал ни свет ни заря, чтобы закончить работу до жары.
2) Я сначала смотрел на него из окна.
3) С этого дня дело пошло веселее.
4) Он только повторял, что хороший мастер должен семь раз отмерить.
5) Через неделю в домик заселилась первая пара скворцов.', NULL, '14', 'short', 10) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (311, 'Лексический анализ. Выпишите синоним из указанного диапазона предложений.', '(1) Каждую весну дед собирал во дворе дощечки и принимался мастерить скворечники. (2) Он вставал ни свет ни заря, чтобы закончить работу до жары. (3) Я сначала смотрел на него из окна и не понимал, зачем тратить время на птиц. (4) Но однажды дед позвал меня в мастерскую и дал маленький молоток. (5) С этого дня дело пошло веселее. (6) Мы вместе выбирали доски, спорили из-за размеров крыши и смеялись, когда гвозди упрямо гнулись. (7) Дед не ругался и никогда не делал всё за меня. (8) Он только повторял, что хороший мастер должен семь раз отмерить. (9) Когда скворечник наконец повис на яблоне, я ходил вокруг него как именинник. (10) Через неделю в домик заселилась первая пара скворцов. (11) Тогда я понял, что мы строили не просто коробку, а жильё для живых существ. (12) С тех пор весеннюю работу я ждал не меньше деда.

Среди предложений 1–6 найдите синоним к слову ДОМ из предложения 10. Выпишите этот синоним.', NULL, 'скворечники', 'short', 11) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (312, 'Используя прочитанный текст, выполните на отдельном листе ТОЛЬКО ОДНО из заданий (1, 2 или 3). Перед написанием сочинения запишите номер выбранного задания (1, 2 или 3).', '1. Напишите сочинение-рассуждение на тему «Какие средства языка использовал автор для создания образа Сени Голубкина?».

Приведите в сочинении два примера из прочитанного текста, подтверждающих Ваши рассуждения. Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой полностью переписанный или пересказанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком.

2. Напишите сочинение-рассуждение. Объясните, как Вы понимаете смысл фрагмента текста: «Он не проникся благодарностью к Ване Белову, напротив, именно с тех пор и невзлюбил его. Голубкин не простил благородства, как не прощал он грамотности тем, кто ему же помогал находить ошибки».

Приведите в сочинении два примера-иллюстрации из прочитанного текста, подтверждающих Ваши рассуждения.

Приводя примеры, указывайте номера нужных предложений или применяйте цитирование.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой пересказанный или полностью переписанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком.

3. Напишите сочинение-рассуждение на тему «Как характеризуют человека его нравственные ценности?». Дайте обоснованный ответ на вопрос, сформулированный в теме сочинения.

Приведите в сочинении два примера, подтверждающих Ваши рассуждения: один пример — из прочитанного текста, а другой — из прочитанного текста или из Вашего жизненного опыта. (Не учитываются примеры, источниками которых являются комикс, аниме, манга, фанфик, графический роман, компьютерная игра и другие подобные виды представления информации.) Приводя примеры, Вы можете использовать различные способы обращения к прочитанному тексту.

Объём сочинения должен составлять не менее 70 слов.

Если сочинение представляет собой пересказанный или полностью переписанный исходный текст без каких бы то ни было комментариев, то такая работа оценивается нулём баллов.

Сочинение пишите аккуратно, разборчивым почерком.', NULL, '', 'long', 12) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (401, 'Укажите варианты ответов, в которых верно определена грамматическая основа в одном из предложений или в одной из частей сложного предложения текста. Запишите номера ответов.', '(1) На рассвете туман стелился над лугом и медленно уходил к реке.
(2) В низине были слышны голоса пастухов.
(3) Колокольчики, верные приметы лета, звенели под ветром.
(4) Люди, которые шли по тропе, разговаривали вполголоса.
(5) Утро казалось особенно свежим.

1) туман стелился (предложение 1)
2) были слышны голоса (предложение 2)
3) приметы звенели (предложение 3)
4) которые шли (предложение 4)
5) утро казалось (предложение 5)', NULL, '145', 'short', 1) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (402, 'Укажите варианты ответов, в которых даны верные характеристики предложений текста. Запишите номера ответов.', '(1) На рассвете туман стелился над лугом и медленно уходил к реке.
(2) В низине были слышны голоса пастухов.
(3) Колокольчики, верные приметы лета, звенели под ветром.
(4) Люди, которые шли по тропе, разговаривали вполголоса.
(5) Утро казалось особенно свежим.

1) В предложении 1 есть однородные сказуемые.
2) Предложение 2 односоставное назывное.
3) Предложение 3 осложнено приложением.
4) В предложении 4 есть придаточное определительное.
5) Предложение 5 сложноподчинённое.', NULL, '134', 'short', 2) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (403, 'Установите соответствие между пунктуационными правилами и предложениями, которые могут служить примерами для приведённых правил. Запишите цифры в порядке АБВ.', 'ПУНКТУАЦИОННЫЕ ПРАВИЛА

А) Между подлежащим и сказуемым ставится тире.
Б) Между частями сложного бессоюзного предложения ставится двоеточие, если вторая часть указывает на причину.
В) Между частями сложносочинённого предложения ставится запятая.

ПРЕДЛОЖЕНИЯ

1) Знание — сила.
2) Я ускорил шаг: начинался дождь.
3) Небо потемнело, и вдали сверкнула молния.
4) Когда стемнело, мы вернулись домой.
5) Ветер шевелил листья берёз.', NULL, '123', 'short', 3) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (404, 'Расставьте знаки препинания. Укажите цифры, на месте которых должно стоять тире.', 'Старый дуб (1) хранитель этой поляны. Его ветви (2) широкие и крепкие. Лучшее время для прогулки здесь (3) раннее утро. За холмом виднелась деревня (4) и полоска леса. Тишина вокруг (5) редкая удача для городского человека.', NULL, '135', 'short', 4) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (405, 'Укажите варианты ответов, в которых дано верное объяснение написания выделенного слова. Запишите номера ответов.', '1) ПРИГОРОДНЫЙ — приставка ПРИ- обозначает расположение рядом.
2) РАСШИТЬ — на конце приставки перед звонким согласным пишется С.
3) ЦЫФРА — после Ц в корне пишется Ы.
4) НЕ ЗАКОНЧЕННАЯ ВОВРЕМЯ работа — причастие с зависимым словом пишется раздельно.
5) КАСАТЬСЯ — в корне пишется А, потому что есть суффикс -А-.', NULL, '145', 'short', 5) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (406, 'Прочитайте текст. Вставьте пропущенные буквы. Укажите все цифры, на месте которых пишется буква О.', 'Мы подошли к зар(1)..слям у реки, прик(2)..снулись к влажной траве и увидели, как в тр(3)..стнике качается лодка. Вдруг из-за обл(4)..ков вышло солнце и всё оз(5)..рилось светом.', NULL, '12345', 'short', 6) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (407, 'Раскройте скобки и запишите слово в соответствующей форме, соблюдая нормы современного русского литературного языка.', 'До крепости оставалось менее (девятьсот) метров.', NULL, 'девятисот', 'short', 7) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (408, 'Синтаксический анализ. Замените словосочетание, построенное на основе управления, синонимичным словосочетанием со связью примыкание. Напишите получившееся словосочетание, соблюдая нормы современного русского литературного языка.', 'Замените словосочетание «смотрел с удивлением» синонимичным словосочетанием со связью примыкание.', NULL, 'смотрел удивлённо', 'short', 8) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (409, 'Анализ содержания текста. Какие из высказываний соответствуют содержанию текста? Укажите номера ответов.', '(1) Утро перед школьной ярмаркой выдалось суматошным. (2) Мы с одноклассниками таскали столы, развешивали плакаты и спорили из-за того, где лучше поставить коробку с выпечкой. (3) Больше всех волновалась Лиза: именно ей поручили объявлять начало ярмарки. (4) Обычно она говорила легко и уверенно, но в тот день почему-то сбивалась на каждом слове. (5) За час до открытия Лиза призналась мне, что боится выступать перед родителями и учителями. (6) Я удивился: до этого она всегда казалась человеком, которому море по колено. (7) Тогда мы ушли в пустой класс и начали репетировать. (8) Сначала Лиза читала текст тихо и не поднимала глаз. (9) Потом голос её стал ровнее, а в конце она даже улыбнулась. (10) Когда ярмарка началась, Лиза вышла к микрофону и без запинки произнесла всё объявление. (11) После этого она смеялась и говорила, что страх оказался гораздо меньше, чем рисовало воображение.

1) Лиза совсем не переживала перед выступлением.
2) Рассказчик помог Лизе подготовиться.
3) Лиза отказалась выходить к микрофону.
4) После репетиции девушка почувствовала себя увереннее.
5) Ярмарку отменили из-за волнения Лизы.', NULL, '24', 'short', 9) ON CONFLICT (id) DO UPDATE SET text = EXCLUDED.text, body = EXCLUDED.body, image = EXCLUDED.image, correct_answer = EXCLUDED.correct_answer, answer_type = EXCLUDED.answer_type, topic_id = EXCLUDED.topic_id;
INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (410, 'Анализ средств выразительности. Укажите варианты ответов, в которых средством выразительности речи является фразеологизм.', '(1) Утро перед школьной ярмаркой выдалось суматошным. (2) Мы с одноклассниками таскали столы, развешивали плакаты и спорили из-за того, где лучше поставить коробку с выпечкой. (3) Больше всех волновалась Лиза: именно ей поручили объявлять начало ярмарки. (4) Обычно она говорила легко и уверенно, но в тот день почему-то сбивалась на каждом слове. (5) За час до открытия Лиза призналась мне, что боится выступать перед родителями и учителями. (6) Я удивился: до этого она всегда казалась человеком, которому море по колено. (7) Тогда мы ушли в пустой класс и начали репетировать. (8) Сначала Лиза читала текст тихо и не поднимала глаз. (9) Потом голос её стал ровнее, а в конце она даже улыбнулась. (10) Когда ярмарка началась, Лиза вышла к микрофону и без запинки произнесла всё объявление. (11) После этого она смеялась и говорила, что страх оказался гораздо меньше, чем рисовало воображение.

1) Утро перед школьной ярмаркой выдалось суматошным.
2) До этого она всегда казалась человеком, которому море по колено.
