INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (411, 'Лексический анализ. Выпишите синоним из указанного диапазона предложений.', '(1) Утро перед школьной ярмаркой выдалось суматошным. (2) Мы с одноклассниками таскали столы, развешивали плакаты и спорили из-за того, где лучше поставить коробку с выпечкой. (3) Больше всех волновалась Лиза: именно ей поручили объявлять начало ярмарки. (4) Обычно она говорила легко и уверенно, но в тот день почему-то сбивалась на каждом слове. (5) За час до открытия Лиза призналась мне, что боится выступать перед родителями и учителями. (6) Я удивился: до этого она всегда казалась человеком, которому море по колено. (7) Тогда мы ушли в пустой класс и начали репетировать. (8) Сначала Лиза читала текст тихо и не поднимала глаз. (9) Потом голос её стал ровнее, а в конце она даже улыбнулась. (10) Когда ярмарка началась, Лиза вышла к микрофону и без запинки произнесла всё объявление. (11) После этого она смеялась и говорила, что страх оказался гораздо меньше, чем рисовало воображение.

