INSERT INTO questions (id, text, body, image, correct_answer, answer_type, topic_id) VALUES (601, 'Укажите варианты ответов, в которых верно определена грамматическая основа в одном из предложений или в одной из частей сложного предложения текста. Запишите номера ответов.', '(1) После дождя дорога блестела и тянулась к лесу.
